// Node defines model for Node.
type Node struct {
	AgentVersion string             `json:"agent_version"`
	EnrolledAt   time.Time          `json:"enrolled_at"`
	Id           openapi_types.UUID `json:"id"`

	// IsSiteHub S8.3 (D2): true iff this gateway is the org's transit HUB — a PROJECTION of the ONE hub election (`electSiteHub`, the endpoint-bearing gateway with the lowest id; single hub v1). Backend-derived so the UI never re-elects the hub in TS. Absent/false for non-gateway nodes and NAT-only meshes.
	IsSiteHub  *bool      `json:"is_site_hub,omitempty"`
	LastSeenAt *time.Time `json:"last_seen_at,omitempty"`

	// MaxPolicyVersion S8.3 (CW): the agent's REPORTED max-supported policy version — observability (a reported fact, OUTSIDE the compile hash; no ProtocolVersion bump). NULL = never reported (a pre-upgrade agent): absence reads as BELOW the current ceiling, never unknown-treated-as-ready (S7.5.3 absence-is- not-compliance, applied to version readiness). The UI's cross-site upgrade warning names the gateways whose max is below the ceiling.
	MaxPolicyVersion *int   `json:"max_policy_version"`
	Name             string `json:"name"`

	// PolicyDegraded Zero Trust (enterprise): a single CONSERVATIVE health signal for the gateway's policy enforcement. degraded = (apply error) OR (an enforcing apply is currently failing) OR (enforcing AND the policy in force differs from what the control plane would push now). The field errs toward OVER-reporting (a false "degraded" is an annoyance; a false "healthy" is the silent-blackhole class) — except in the provider can't-determine window, where the gateway is guaranteed on its last-good fail-closed policy (never open, never blackholing from this cause). The differentiated breakdown (which kind of degraded) + badge UX is S7.4, reading the same agent-reported JSONB.
	PolicyDegraded *bool `json:"policy_degraded,omitempty"`

	// PolicyDegradedKind Zero Trust (enterprise, S7.4b): the ADVISORY differentiated health kind — display detail over `policy_degraded`, which stays the sole authoritative signal (nothing keys logic on this). `desync_unknown` is a FIRST-CLASS honest state (compile-hash unavailable, or the gateway stopped reporting) — it means "cannot determine", NEVER healthy and NEVER a specific kind. `converging` is a normal push settling (< the report-cadence debounce) and must not alarm; `silent_desync` is a stuck pushed≠applied past the debounce with fresh reports. `unsupported_policy_version` (S8.1 D1): the agent REFUSED the compiled artifact (its Version exceeds what the agent can apply) and went deny-all — the ONE kind whose remedy is edition-independent and operator-side: upgrade the agent. Set for any edition (the version gate lives on the agent, not the policy engine). `site_hub_down` / `site_link_down` (S8.2 H5/B2): a SITE gateway's site-to-site link has no fresh handshake — the hub is unreachable (`site_hub_down`, CP-derived: no public-endpoint carrier) or a spoke link is dead (`site_link_down`, agent-reported staleness). A down site bridge is never green. Hub outranks a single spoke link-down. `site_subnet_unreachable` (S8.2c D3): the gateway advertises a local site subnet but NO host address is inside it (bridge-trapped wg0 / misconfig) — agent-reported and INDEPENDENT of link state, so it catches the reassuring-green shape where the link handshake is fresh yet forwarded traffic can't be sourced onto the LAN. Ranks below the link-down kinds (a dead link masks it).
	PolicyDegradedKind *NodePolicyDegradedKind `json:"policy_degraded_kind,omitempty"`

	// SiteId S8.3 (D2/CH): the site this gateway is bound to (null = not a site gateway). The topology view joins nodes to sites by this field — a site's gateways are the nodes with this site_id, rendered as a LIST (many nodes → one site scales to future HA; the UI never assumes one-gateway-per-site).
	SiteId *openapi_types.UUID `json:"site_id"`
	Status NodeStatus          `json:"status"`
}

// NodePolicyDegradedKind Zero Trust (enterprise, S7.4b): the ADVISORY differentiated health kind — display detail over `policy_degraded`, which stays the sole authoritative signal (nothing keys logic on this). `desync_unknown` is a FIRST-CLASS honest state (compile-hash unavailable, or the gateway stopped reporting) — it means "cannot determine", NEVER healthy and NEVER a specific kind. `converging` is a normal push settling (< the report-cadence debounce) and must not alarm; `silent_desync` is a stuck pushed≠applied past the debounce with fresh reports. `unsupported_policy_version` (S8.1 D1): the agent REFUSED the compiled artifact (its Version exceeds what the agent can apply) and went deny-all — the ONE kind whose remedy is edition-independent and operator-side: upgrade the agent. Set for any edition (the version gate lives on the agent, not the policy engine). `site_hub_down` / `site_link_down` (S8.2 H5/B2): a SITE gateway's site-to-site link has no fresh handshake — the hub is unreachable (`site_hub_down`, CP-derived: no public-endpoint carrier) or a spoke link is dead (`site_link_down`, agent-reported staleness). A down site bridge is never green. Hub outranks a single spoke link-down. `site_subnet_unreachable` (S8.2c D3): the gateway advertises a local site subnet but NO host address is inside it (bridge-trapped wg0 / misconfig) — agent-reported and INDEPENDENT of link state, so it catches the reassuring-green shape where the link handshake is fresh yet forwarded traffic can't be sourced onto the LAN. Ranks below the link-down kinds (a dead link masks it).
type NodePolicyDegradedKind string

